import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Ensure input length does not exceed buffer size
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        if (input.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Truncating to " + bufferSize + " characters.");
            input = input.substring(0, bufferSize);
        }

        // Copy input into buffer safely
        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

